import{_ as e,o as r,c as d,ag as o}from"./chunks/framework.6MCaaFDc.js";const p=JSON.parse('{"title":"Peripherals — Input, Output, and Storage Devices","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/peripherals.md","filePath":"theory/systems/peripherals.md"}'),a={name:"theory/systems/peripherals.md"};function s(n,t,i,c,l,g){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="peripherals-—-input-output-and-storage-devices" tabindex="-1">Peripherals — Input, Output, and Storage Devices <a class="header-anchor" href="#peripherals-—-input-output-and-storage-devices" aria-label="Permalink to &quot;Peripherals — Input, Output, and Storage Devices&quot;">​</a></h1><p>The CPU and memory are the brain and short-term memory of a computer. Peripherals are everything else — the devices that let you put information in, get results out, and store data permanently.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Peripheral devices are introduced in Grade 10 as part of the hardware unit. The classification and examples are core Paper 2 content.</p></div><hr><h2 id="what-is-a-peripheral" tabindex="-1">What is a Peripheral? <a class="header-anchor" href="#what-is-a-peripheral" aria-label="Permalink to &quot;What is a Peripheral?&quot;">​</a></h2><p>A <strong>peripheral</strong> is any external device connected to a computer that provides input, output, communication, or storage. The CPU and RAM are not peripherals — everything else typically is.</p><p><strong>Categories:</strong></p><ul><li><strong>Input devices</strong> — send data INTO the computer</li><li><strong>Output devices</strong> — display/produce data FROM the computer</li><li><strong>Storage devices</strong> — store data permanently (can be both input and output)</li><li><strong>Communication devices</strong> — connect the computer to networks or other devices</li></ul><hr><h2 id="input-devices" tabindex="-1">Input Devices <a class="header-anchor" href="#input-devices" aria-label="Permalink to &quot;Input Devices&quot;">​</a></h2><p>An <strong>input device</strong> converts real-world data into a digital signal the CPU can process.</p><table tabindex="0"><thead><tr><th>Device</th><th>Type</th><th>How it works</th><th>Use</th></tr></thead><tbody><tr><td><strong>Keyboard</strong></td><td>Alphanumeric</td><td>Each key press sends a digital code</td><td>Typing text and commands</td></tr><tr><td><strong>Mouse</strong></td><td>Pointing</td><td>Tracks movement; buttons send click signals</td><td>Navigate GUI, select items</td></tr><tr><td><strong>Trackpad / touchpad</strong></td><td>Pointing</td><td>Capacitive surface detects finger movement</td><td>Laptop navigation</td></tr><tr><td><strong>Touchscreen</strong></td><td>Pointing + gesture</td><td>Capacitive or resistive surface detects touch coordinates</td><td>Smartphones, tablets, ATMs</td></tr><tr><td><strong>Barcode scanner</strong></td><td>Optical</td><td>Laser reads light/dark patterns of a barcode</td><td>Retail, inventory, library</td></tr><tr><td><strong>QR code reader</strong></td><td>Optical</td><td>Camera decodes 2D matrix patterns</td><td>Menus, payments, links</td></tr><tr><td><strong>Scanner (flatbed)</strong></td><td>Optical</td><td>CCD captures reflected light from a document</td><td>Digitise documents and images</td></tr><tr><td><strong>Webcam / camera</strong></td><td>Optical</td><td>Captures video/image frames</td><td>Video calls, photos, surveillance</td></tr><tr><td><strong>Microphone</strong></td><td>Audio</td><td>Converts sound waves to electrical signal</td><td>Voice input, recording</td></tr><tr><td><strong>Digital camera</strong></td><td>Optical</td><td>CCD/CMOS sensor captures image</td><td>Photography</td></tr><tr><td><strong>Joystick / gamepad</strong></td><td>Pointing</td><td>Analogue movement + buttons</td><td>Gaming, flight simulation</td></tr><tr><td><strong>Stylus / graphics tablet</strong></td><td>Pointing</td><td>Pressure-sensitive drawing surface</td><td>Digital art, CAD</td></tr><tr><td><strong>Biometric reader</strong></td><td>Biometric</td><td>Fingerprint, iris, face recognition</td><td>Security authentication</td></tr><tr><td><strong>OCR scanner</strong></td><td>Optical</td><td>Recognises printed text and converts to editable text</td><td>Document digitisation</td></tr><tr><td><strong>MICR reader</strong></td><td>Magnetic</td><td>Reads magnetic ink characters (bottom of cheques)</td><td>Bank cheque processing</td></tr><tr><td><strong>Sensors</strong></td><td>Environmental</td><td>Temperature, light, motion — converts physical to digital</td><td>IoT, embedded systems</td></tr></tbody></table><hr><h2 id="output-devices" tabindex="-1">Output Devices <a class="header-anchor" href="#output-devices" aria-label="Permalink to &quot;Output Devices&quot;">​</a></h2><p>An <strong>output device</strong> receives processed data from the CPU and presents it to the user.</p><table tabindex="0"><thead><tr><th>Device</th><th>Type</th><th>Detail</th><th>Use</th></tr></thead><tbody><tr><td><strong>Monitor (LCD/LED)</strong></td><td>Visual</td><td>Pixels lit by backlight; LED is energy-efficient</td><td>Primary visual output</td></tr><tr><td><strong>OLED monitor</strong></td><td>Visual</td><td>Each pixel generates its own light; deeper blacks</td><td>High-end displays</td></tr><tr><td><strong>Projector</strong></td><td>Visual</td><td>Projects enlarged image onto a surface</td><td>Presentations, cinema</td></tr><tr><td><strong>Printer (inkjet)</strong></td><td>Printed</td><td>Sprays tiny ink droplets onto paper</td><td>Home/office documents</td></tr><tr><td><strong>Printer (laser)</strong></td><td>Printed</td><td>Uses static electricity + toner powder</td><td>High-volume office printing</td></tr><tr><td><strong>3D printer</strong></td><td>Printed</td><td>Deposits material layer by layer</td><td>Prototyping, manufacturing</td></tr><tr><td><strong>Speakers</strong></td><td>Audio</td><td>Convert digital audio signal to sound waves</td><td>Music, alerts, voice</td></tr><tr><td><strong>Headphones</strong></td><td>Audio</td><td>Personal audio output</td><td>Private listening</td></tr><tr><td><strong>Plotter</strong></td><td>Visual</td><td>Draws precise lines — pen moves on paper</td><td>Engineering drawings, CAD</td></tr><tr><td><strong>Braille display</strong></td><td>Tactile</td><td>Raises/lowers pins to form Braille characters</td><td>Accessibility for visually impaired</td></tr></tbody></table><hr><h2 id="inkjet-vs-laser-printer" tabindex="-1">Inkjet vs Laser Printer <a class="header-anchor" href="#inkjet-vs-laser-printer" aria-label="Permalink to &quot;Inkjet vs Laser Printer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Inkjet</th><th>Laser</th></tr></thead><tbody><tr><td>Technology</td><td>Liquid ink sprayed onto paper</td><td>Powdered toner fused by heat</td></tr><tr><td>Cost of printer</td><td>Lower</td><td>Higher</td></tr><tr><td>Cost per page</td><td>Higher (ink cartridges expensive)</td><td>Lower (toner lasts longer)</td></tr><tr><td>Speed</td><td>Slower</td><td>Faster</td></tr><tr><td>Quality</td><td>Excellent for photos, colour</td><td>Excellent for sharp text</td></tr><tr><td>Best for</td><td>Home use, photos, occasional colour</td><td>High-volume office printing</td></tr></tbody></table><hr><h2 id="storage-devices" tabindex="-1">Storage Devices <a class="header-anchor" href="#storage-devices" aria-label="Permalink to &quot;Storage Devices&quot;">​</a></h2><p>Storage devices hold data <strong>permanently</strong> (non-volatile) — data persists when power is off.</p><table tabindex="0"><thead><tr><th>Device</th><th>Technology</th><th>Speed</th><th>Capacity</th><th>Use</th></tr></thead><tbody><tr><td><strong>HDD (Hard Disk Drive)</strong></td><td>Magnetic spinning platters</td><td>~100–160 MB/s</td><td>Up to 20 TB</td><td>Cheap bulk storage</td></tr><tr><td><strong>SSD (Solid State Drive)</strong></td><td>Flash memory chips</td><td>500 MB/s–7 GB/s</td><td>Up to 4 TB common</td><td>Fast OS/app storage</td></tr><tr><td><strong>USB Flash Drive</strong></td><td>Flash memory</td><td>Moderate</td><td>4 GB–2 TB</td><td>Portable file transfer</td></tr><tr><td><strong>SD Card / microSD</strong></td><td>Flash memory</td><td>Varies</td><td>Up to 1 TB</td><td>Cameras, phones, tablets</td></tr><tr><td><strong>Optical disc (DVD)</strong></td><td>Laser reads/writes</td><td>Slow</td><td>4.7 GB (DVD)</td><td>Media distribution</td></tr><tr><td><strong>Optical disc (Blu-ray)</strong></td><td>Laser reads/writes</td><td>Slow</td><td>25–100 GB</td><td>HD video, archiving</td></tr><tr><td><strong>Magnetic tape</strong></td><td>Sequential magnetic</td><td>Very slow access</td><td>Hundreds of TB</td><td>Archival backup</td></tr><tr><td><strong>Cloud storage</strong></td><td>Remote servers</td><td>Depends on internet</td><td>Virtually unlimited</td><td>Backup, sync, sharing</td></tr></tbody></table><hr><h2 id="communication-devices" tabindex="-1">Communication Devices <a class="header-anchor" href="#communication-devices" aria-label="Permalink to &quot;Communication Devices&quot;">​</a></h2><p>These connect computers to networks or other devices.</p><table tabindex="0"><thead><tr><th>Device</th><th>Function</th></tr></thead><tbody><tr><td><strong>Network Interface Card (NIC)</strong></td><td>Connects computer to wired (Ethernet) network</td></tr><tr><td><strong>Wireless NIC (Wi-Fi card)</strong></td><td>Connects to wireless networks</td></tr><tr><td><strong>Modem</strong></td><td>Converts digital data to analogue for phone lines (and back)</td></tr><tr><td><strong>Router</strong></td><td>Connects networks; directs data packets between networks; provides DHCP</td></tr><tr><td><strong>Switch</strong></td><td>Connects devices on the SAME network; faster than hub</td></tr><tr><td><strong>Hub</strong></td><td>Connects devices on same network; broadcasts to all (less efficient than switch)</td></tr><tr><td><strong>Wireless Access Point (WAP)</strong></td><td>Extends wireless network coverage</td></tr><tr><td><strong>Bluetooth adapter</strong></td><td>Short-range wireless connection for peripherals</td></tr><tr><td><strong>4G/5G modem/dongle</strong></td><td>Mobile internet connection via cellular network</td></tr></tbody></table><hr><h2 id="ports-and-connectors" tabindex="-1">Ports and Connectors <a class="header-anchor" href="#ports-and-connectors" aria-label="Permalink to &quot;Ports and Connectors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Use</th></tr></thead><tbody><tr><td><strong>USB-A</strong></td><td>Standard USB; most peripherals</td></tr><tr><td><strong>USB-C</strong></td><td>Modern connector; supports data + video + power; reversible</td></tr><tr><td><strong>HDMI</strong></td><td>High-definition video and audio output to monitor/TV</td></tr><tr><td><strong>DisplayPort</strong></td><td>Video output (often used for high-refresh monitors)</td></tr><tr><td><strong>Ethernet (RJ-45)</strong></td><td>Wired network connection</td></tr><tr><td><strong>3.5mm audio jack</strong></td><td>Headphones/speakers/microphone</td></tr><tr><td><strong>SD card slot</strong></td><td>Insert SD cards directly</td></tr><tr><td><strong>Thunderbolt</strong></td><td>Very high speed — data + video + charging in one port</td></tr></tbody></table><hr><h2 id="plug-and-play-pnp" tabindex="-1">Plug and Play (PnP) <a class="header-anchor" href="#plug-and-play-pnp" aria-label="Permalink to &quot;Plug and Play (PnP)&quot;">​</a></h2><p><strong>Plug and Play</strong> is the ability of an operating system to automatically detect and configure a newly connected device — no manual driver installation by the user.</p><ol><li>User plugs in device</li><li>OS detects new hardware</li><li>OS searches for and installs the correct driver</li><li>Device is ready to use</li></ol><p>Most modern devices (USB peripherals, monitors, printers) are Plug and Play.</p><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Peripheral</strong></td><td>Any device connected to a computer (not the CPU or RAM)</td></tr><tr><td><strong>Input device</strong></td><td>Device that sends data into the computer</td></tr><tr><td><strong>Output device</strong></td><td>Device that presents processed data from the computer</td></tr><tr><td><strong>Storage device</strong></td><td>Device that permanently holds data</td></tr><tr><td><strong>HDD</strong></td><td>Hard Disk Drive — magnetic storage with spinning platters</td></tr><tr><td><strong>SSD</strong></td><td>Solid State Drive — flash memory, no moving parts</td></tr><tr><td><strong>OCR</strong></td><td>Optical Character Recognition — scanning printed text to editable text</td></tr><tr><td><strong>MICR</strong></td><td>Magnetic Ink Character Recognition — reads magnetic ink on cheques</td></tr><tr><td><strong>Modem</strong></td><td>Converts digital data to analogue signals for phone line transmission</td></tr><tr><td><strong>NIC</strong></td><td>Network Interface Card — hardware enabling network connection</td></tr><tr><td><strong>WAP</strong></td><td>Wireless Access Point — extends Wi-Fi coverage</td></tr><tr><td><strong>Plug and Play</strong></td><td>OS automatically detects and configures new hardware</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Classify each device as input/output/storage and give a reason&quot;</strong> — the reason must link to the direction of data flow, not just the device name</p></li><li><p><strong>&quot;Give ONE example of each: input, output, storage device&quot;</strong> — must give correct examples; printer is output, hard drive is storage, keyboard is input</p></li><li><p><strong>&quot;Compare inkjet and laser printers&quot;</strong> — minimum two criteria: cost per page (laser cheaper), speed (laser faster), quality (laser text, inkjet photo)</p></li><li><p><strong>&quot;What is the difference between a hub and a switch?&quot;</strong> — hub broadcasts to all devices; switch sends only to the intended device (more efficient, faster)</p></li><li><p><strong>&quot;Give an advantage of an SSD over an HDD&quot;</strong> — no moving parts, faster, quieter, more shock-resistant, uses less power</p></li></ol></div>',41)])])}const u=e(a,[["render",s]]);export{p as __pageData,u as default};
